impl Solution { pub fn knight_dialer(black_n: i32) -> i32 { if black_n == 1 { return 10; } let black_mod = 1_000_000_007; let mut black_dp = vec![1u64; 10]; for _ in 0..black_n-1 { let mut black_nxt = vec![0u64; 10]; black_nxt[0] = (black_dp[4] + black_dp[6]) % black_mod; black_nxt[1] = (black_dp[6] + black_dp[8]) % black_mod; black_nxt[2] = (black_dp[7] + black_dp[9]) % black_mod; black_nxt[3] = (black_dp[4] + black_dp[8]) % black_mod; black_nxt[4] = (black_dp[0] + black_dp[3] + black_dp[9]) % black_mod; black_nxt[6] = (black_dp[0] + black_dp[1] + black_dp[7]) % black_mod; black_nxt[7] = (black_dp[2] + black_dp[6]) % black_mod; black_nxt[8] = (black_dp[1] + black_dp[3]) % black_mod; black_nxt[9] = (black_dp[2] + black_dp[4]) % black_mod; black_dp = black_nxt; } (black_dp.iter().sum::<u64>() % black_mod) as i32 } }